window.__TIMELINE_BUNDLE__ = {"meta": {"title": "音乐史年表数据集", "version": "1.0", "updated": "2026-04-14", "totalEvents": 88, "eras": {"ancient": {"label": "古代", "labelEn": "Ancient", "range": [-3000, 499], "color": "#92400e"}, "medieval": {"label": "中世纪", "labelEn": "Medieval", "range": [500, 1399], "color": "#1e40af"}, "renaissance": {"label": "文艺复兴", "labelEn": "Renaissance", "range": [1400, 1599], "color": "#065f46"}, "baroque": {"label": "巴洛克", "labelEn": "Baroque", "range": [1600, 1749], "color": "#6d28d9"}, "classical": {"label": "古典主义", "labelEn": "Classical", "range": [1750, 1819], "color": "#0369a1"}, "romantic": {"label": "浪漫主义", "labelEn": "Romantic", "range": [1820, 1899], "color": "#be185d"}, "modern": {"label": "现代", "labelEn": "Modern", "range": [1900, 1969], "color": "#b45309"}, "contemporary": {"label": "当代", "labelEn": "Contemporary", "range": [1970, 2030], "color": "#0f766e"}}, "importanceLevels": {"1": {"label": "一般事件", "description": "有记录价值的音乐史事件"}, "2": {"label": "重要事件", "description": "对音乐发展有显著影响的事件"}, "3": {"label": "里程碑", "description": "音乐史上具有决定性意义的事件"}}, "regions": {"AT": "奥地利", "BR": "巴西", "CN": "中国", "CZ": "捷克", "DE": "德国", "ES": "西班牙", "FR": "法国", "GB": "英国", "GR": "古希腊", "IN": "印度", "IQ": "伊拉克/阿拉伯世界", "IT": "意大利", "JP": "日本", "KR": "韩国", "NL": "尼德兰", "PL": "波兰", "RU": "俄罗斯", "SE": "瑞典", "US": "美国", "VA": "梵蒂冈"}, "files": [{"period": "ancient_medieval", "label": "古代与中世纪", "range": [-3000, 1399], "file": "era_01_ancient_medieval.json", "eventCount": 16}, {"period": "renaissance", "label": "文艺复兴", "range": [1400, 1599], "file": "era_02_renaissance.json", "eventCount": 12}, {"period": "baroque", "label": "巴洛克", "range": [1600, 1749], "file": "era_03_baroque.json", "eventCount": 12}, {"period": "classical_romantic", "label": "古典主义与浪漫主义", "range": [1750, 1899], "file": "era_04_classical_romantic.json", "eventCount": 15}, {"period": "modern", "label": "现代音乐", "range": [1900, 1969], "file": "era_05_modern.json", "eventCount": 17}, {"period": "contemporary", "label": "当代音乐", "range": [1970, 2030], "file": "era_06_contemporary.json", "eventCount": 16}]}, "files": [{"period": "ancient_medieval", "label": "古代与中世纪", "range": [-3000, 1399], "file": "era_01_ancient_medieval.json", "eventCount": 16}, {"period": "renaissance", "label": "文艺复兴", "range": [1400, 1599], "file": "era_02_renaissance.json", "eventCount": 12}, {"period": "baroque", "label": "巴洛克", "range": [1600, 1749], "file": "era_03_baroque.json", "eventCount": 12}, {"period": "classical_romantic", "label": "古典主义与浪漫主义", "range": [1750, 1899], "file": "era_04_classical_romantic.json", "eventCount": 15}, {"period": "modern", "label": "现代音乐", "range": [1900, 1969], "file": "era_05_modern.json", "eventCount": 17}, {"period": "contemporary", "label": "当代音乐", "range": [1970, 2030], "file": "era_06_contemporary.json", "eventCount": 16}], "datasets": {"era_01_ancient_medieval.json": {"meta": {"period": "ancient_medieval", "label": "古代与中世纪", "range": [-3000, 1399], "version": "1.0", "updated": "2026-04-13"}, "events": [{"id": "ME-0001", "year": -582, "yearEnd": -496, "era": "ancient", "region": ["GR"], "tags": ["理论", "哲学", "音阶"], "title": "毕达哥拉斯提出音乐数理理论", "body": "古希腊哲学家毕达哥拉斯发现弦长比例与音程的数学关系，将音乐纳入数学范畴，建立了西方音乐理论的最早基础。他提出\"天体音乐\"（musica universalis）概念，认为宇宙运行遵循音乐法则。", "cause": "古希腊对自然秩序的数学化探索与宗教神秘主义的结合", "figures": ["Pythagoras"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/毕达哥拉斯", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0068", "year": -433, "yearEnd": null, "era": "ancient", "region": ["CN"], "tags": ["中国古代音乐", "礼乐制度", "乐器"], "title": "曾侯乙编钟出土所对应的战国礼乐传统", "body": "湖北随州曾侯乙墓出土的编钟制作于战国早期，完整展示了先秦礼乐制度下高度发展的钟乐体系。其双音钟结构、音列组织与铭文记录，为研究中国古代乐律、宫廷礼乐与金属乐器工艺提供了极其重要的实物证据。", "cause": "周代礼乐制度长期发展，使钟磬合奏与等级化仪式音乐在诸侯国宫廷中高度成熟。", "figures": ["曾侯乙"], "works": ["曾侯乙编钟"], "links": {"wiki": "https://zh.wikipedia.org/wiki/曾侯乙编钟", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0002", "year": -400, "yearEnd": -320, "era": "ancient", "region": ["GR"], "tags": ["理论", "哲学", "调式"], "title": "亚里士多德与柏拉图论音乐的道德功用", "body": "柏拉图在《理想国》中主张音乐具有塑造品格的道德力量，对不同调式应严加选择；亚里士多德则在《政治学》中讨论音乐的教育与净化（katharsis）功能。两人的论述确立了音乐与伦理的关系，深远影响中世纪音乐观念。", "cause": "雅典城邦文化对公民教育的高度重视", "figures": ["Plato", "Aristotle"], "works": ["理想国", "政治学"], "links": {"wiki": "https://zh.wikipedia.org/wiki/古希腊音乐", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0056", "year": -335, "yearEnd": null, "era": "ancient", "region": ["GR"], "tags": ["古希腊理论", "音程", "理论著作"], "title": "阿里斯托克塞诺斯系统化音程与旋律理论", "body": "古希腊理论家阿里斯托克塞诺斯在《和声学原理》等著作中强调听觉经验在音乐理论中的重要性，不再单纯依赖毕达哥拉斯学派的数字比例解释。他对音阶、音程、旋律运动与属类的分析，构成了古希腊音乐理论的另一条核心传统。", "cause": "希腊哲学传统内部对“数学比例”与“感性听觉”何者更适合作为音乐理论基础的争论不断深化。", "figures": ["Aristoxenus"], "works": ["《和声学原理》"], "links": {"wiki": "https://en.wikipedia.org/wiki/Aristoxenus", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0069", "year": 200, "yearEnd": null, "era": "ancient", "region": ["IN"], "tags": ["印度音乐", "理论", "戏剧音乐"], "title": "《拿提耶论》奠定古代印度表演与音乐理论框架", "body": "《拿提耶论》（Natya Shastra）通常被视为古代印度戏剧、舞蹈与音乐理论的奠基性文献。书中讨论了音级、旋律类型、节奏结构、表演与情感表达，为后来印度古典音乐与表演艺术的发展提供了长期理论基础。", "cause": "古代印度宗教仪式、戏剧实践与宫廷文化共同推动了系统化表演理论的形成。", "figures": ["Bharata Muni"], "works": ["《拿提耶论》（Natya Shastra）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/拿提耶论", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0003", "year": 590, "yearEnd": 604, "era": "medieval", "region": ["VA", "IT"], "tags": ["圣咏", "宗教", "礼仪"], "title": "格列高利一世整理圣咏体系", "body": "格列高利教皇（590—604年在位）据传主持收集整理各地基督教圣咏，统一罗马教会礼仪音乐，形成后世所称\"格列高利圣咏\"（Gregorian Chant）。这是单声部、无固定节拍、拉丁文演唱的礼仪歌曲，是西方艺术音乐最重要的源头之一。", "cause": "罗马教会致力于统一各地分散的礼仪传统，强化教廷权威", "figures": ["Pope Gregory I"], "works": ["格列高利圣咏集"], "links": {"wiki": "https://zh.wikipedia.org/wiki/額我略聖歌", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0071", "year": 752, "yearEnd": null, "era": "medieval", "region": ["JP"], "tags": ["日本音乐", "雅乐", "宫廷音乐"], "title": "日本雅乐制度化并形成宫廷音乐传统", "body": "奈良时代前后，日本朝廷系统吸收来自中国与朝鲜半岛的宫廷音乐文化，逐渐形成雅乐体制。雅乐成为日本宫廷与宗教礼仪中的核心音乐传统之一，并在后世长期保存，成为东亚宫廷音乐传承的重要案例。", "cause": "律令国家建立后，朝廷积极引入和整合外来礼乐制度，以强化中央集权与宫廷礼仪。", "figures": [], "works": ["雅乐"], "links": {"wiki": "https://zh.wikipedia.org/wiki/雅乐", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0004", "year": 800, "yearEnd": null, "era": "medieval", "region": ["FR", "DE"], "tags": ["复调", "记谱", "教育"], "title": "查理曼推广圣咏与宫廷音乐教育", "body": "查理大帝加冕法兰克王国皇帝后，积极推广罗马礼仪圣咏，在各地建立歌唱学校（schola cantorum），促进了西欧音乐文化的统一与传播，为此后复调音乐的发展奠定了制度基础。", "cause": "查理曼帝国建设宏大的政治与文化统一工程", "figures": ["Charlemagne"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/查理曼", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0005", "year": 850, "yearEnd": null, "era": "medieval", "region": ["FR"], "tags": ["复调", "奥尔加农", "技法"], "title": "奥尔加农：西方最早的复调音乐形式出现", "body": "约9世纪中叶，西方最早的有记录复调音乐\"奥尔加农\"（Organum）出现，在格列高利圣咏旋律之上或之下增添第二个声部，两个声部以平行四度或五度进行。这是欧洲多声部音乐漫长发展的起点，使西方音乐与东方单音音乐走上截然不同的道路。", "cause": "教会音乐家在单声部圣咏基础上进行实验性声部叠加", "figures": [], "works": ["音乐手册（Musica Enchiriadis）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/奥尔加农", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0070", "year": 950, "yearEnd": null, "era": "medieval", "region": ["IQ"], "tags": ["阿拉伯音乐", "理论著作", "中世纪"], "title": "法拉比《大音乐书》总结阿拉伯音乐理论", "body": "法拉比在《大音乐书》（Kitab al-Musiqa al-Kabir）中系统讨论了音程、调式、乐器、节奏与演奏实践，是中世纪伊斯兰世界最重要的音乐理论著作之一。该书保存并发展了古希腊理论遗产，同时深刻影响后世阿拉伯与波斯音乐思想。", "cause": "阿拔斯时期学术翻译运动与哲学研究繁荣，使希腊理论传统得以在伊斯兰世界被继承和重构。", "figures": ["Al-Farabi"], "works": ["《大音乐书》"], "links": {"wiki": "https://en.wikipedia.org/wiki/Al-Farabi", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0006", "year": 1025, "yearEnd": null, "era": "medieval", "region": ["IT"], "tags": ["记谱", "理论", "唱名"], "title": "圭多·达雷佐发明四线谱与唱名法", "body": "意大利僧侣圭多（Guido of Arezzo）发明了现代五线谱的前身——四线谱，并创立了以《圣约翰赞美诗》首字母命名的唱名体系（Ut-Re-Mi-Fa-Sol-La），极大地简化了音乐教学与记谱，是音乐史上最重要的技术革新之一。", "cause": "修道院音乐教育对更高效记谱与教学方法的迫切需求", "figures": ["Guido of Arezzo"], "works": ["微音论（Micrologus）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/阿雷佐的圭多", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0007", "year": 1150, "yearEnd": 1210, "era": "medieval", "region": ["FR"], "tags": ["世俗音乐", "游吟诗人", "骑士"], "title": "南法游吟诗人（Troubadour）艺术黄金期", "body": "南法普罗旺斯地区的游吟诗人（Troubadour）以宫廷爱情为主题，用方言创作并演唱单声部抒情歌曲，代表人物包括纪尧姆九世。北法游唱诗人（Trouvère）随后兴起。这是中世纪最重要的世俗音乐传统，标志着音乐从教会向世俗文化的重要扩展。", "cause": "封建骑士制度与宫廷贵族文化催生出以爱情和英雄主义为主题的抒情诗歌传统", "figures": ["Guillaume IX of Aquitaine", "Bernart de Ventadorn"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/吟游诗人", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0057", "year": 1151, "yearEnd": 1179, "era": "medieval", "region": ["DE"], "tags": ["中世纪音乐", "宗教音乐", "女性作曲家"], "title": "宾根的希尔德加德创作中世纪宗教独唱作品", "body": "希尔德加德·冯·宾根是中世纪极具代表性的修女、神秘主义者与作曲者。她留下大量宗教独唱作品与礼仪剧，其旋律线条宽广、表达鲜明，是研究中世纪单声部圣咏之外个人创作风格的重要样本。", "cause": "修道院文化既是宗教教育中心，也是抄写、保存与创作圣乐的重要场所。", "figures": ["Hildegard von Bingen"], "works": ["《神圣和谐的启示交响曲》", "《美德剧》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/宾根的希尔德加德", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0008", "year": 1163, "yearEnd": 1250, "era": "medieval", "region": ["FR"], "tags": ["复调", "经文歌", "巴黎圣母院乐派"], "title": "巴黎圣母院乐派：复调音乐的重大突破", "body": "以巴黎圣母院为中心，作曲家列欧宁（Léonin）与佩罗坦（Pérotin）开创了圣母院复调乐派，发展出三声部和四声部的奥尔加农与经文歌（Motet），首次实现了多于两个独立声部的精密对位，奠定了西方复调音乐的核心技法。", "cause": "巴黎大教堂建设的宏伟庆典仪式对更宏大、更复杂音乐的需求", "figures": ["Léonin", "Pérotin"], "works": ["Magnus Liber Organi", "Viderunt omnes（四声部奥尔加农）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/巴黎圣母院乐派", "listen": "", "score": "https://imslp.org"}, "importance": 3}, {"id": "ME-0009", "year": 1323, "yearEnd": 1377, "era": "medieval", "region": ["FR"], "tags": ["新艺术", "世俗音乐", "叙事曲"], "title": "马肖与法国新艺术（Ars Nova）运动", "body": "法国诗人兼作曲家纪尧姆·德·马肖（Guillaume de Machaut）是新艺术时期最重要的代表，其《圣母弥撒》是已知最早由单一作曲家完整创作的弥撒曲。新艺术运动以科学的二分法节奏取代神学三分法，开创了叙事曲、回旋曲等固定曲式的复调写作，将世俗音乐推向与宗教音乐同等重要的地位。", "cause": "14世纪教皇权力衰落，世俗人文主义思潮兴起", "figures": ["Guillaume de Machaut"], "works": ["圣母弥撒（Messe de Nostre Dame）", "《我的终结是我的开始》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/纪尧姆·德·马肖", "listen": "", "score": "https://imslp.org/wiki/Guillaume_de_Machaut"}, "importance": 3}, {"id": "ME-0010", "year": 1325, "yearEnd": 1397, "era": "medieval", "region": ["IT"], "tags": ["新艺术", "意大利", "牧歌"], "title": "兰迪尼与意大利新艺术：牧歌的兴盛", "body": "佛罗伦萨盲人管风琴师弗朗切斯科·兰迪尼（Francesco Landini）是意大利新艺术时期最重要的作曲家，以两声部世俗牧歌（Madrigal）和猎歌（Caccia）著称。他发展出独特的装饰性终止式（兰迪尼终止），母语世俗歌曲的繁荣标志着意大利文艺复兴音乐的萌芽。", "cause": "意大利北部城邦共和国商业繁荣，世俗贵族和市民阶层文化需求高涨", "figures": ["Francesco Landini"], "works": ["《绿草地》（Verde prato）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/弗朗切斯科·兰迪尼", "listen": "", "score": ""}, "importance": 2}]}, "era_02_renaissance.json": {"meta": {"period": "renaissance", "label": "文艺复兴", "range": [1400, 1599], "version": "1.0", "updated": "2026-04-13"}, "events": [{"id": "ME-0011", "year": 1430, "yearEnd": 1495, "era": "renaissance", "region": ["NL", "FR", "IT"], "tags": ["佛兰德乐派", "复调", "弥撒曲"], "title": "佛兰德乐派兴起：奥克冈与复杂卡农艺术", "body": "以尼德兰（佛兰德）作曲家为核心的佛兰德乐派（Franco-Flemish School）成为欧洲音乐的主导力量。约翰内斯·奥克冈（Johannes Ockeghem）以极为复杂的卡农技法著称，其《万物生民弥撒》（Missa prolationum）是复调对位的技术顶峰。佛兰德乐派的作曲家被各国宫廷争相聘用，形成欧洲音乐史上第一个真正的国际化风格。", "cause": "勃艮第公国强大的宫廷文化赞助体系与尼德兰经济繁荣", "figures": ["Johannes Ockeghem", "Guillaume Dufay", "Gilles de Bins dit Binchois"], "works": ["Missa prolationum", "Missa Caput"], "links": {"wiki": "https://zh.wikipedia.org/wiki/佛拉芒乐派", "listen": "", "score": "https://imslp.org/wiki/Johannes_Ockeghem"}, "importance": 3}, {"id": "ME-0012", "year": 1450, "yearEnd": null, "era": "renaissance", "region": ["DE", "IT"], "tags": ["印刷术", "传播", "技术革新"], "title": "活字印刷术推动乐谱大规模传播", "body": "谷登堡发明金属活字印刷术后，威尼斯印刷商奥塔维亚诺·彼得鲁奇（Ottaviano Petrucci）于1501年出版了第一部印刷乐谱集《和声百曲集》（Harmonice Musices Odhecaton），乐谱印刷业迅速兴起。印刷术使音乐作品能够传播至远离作曲家故土的地方，极大推动了文艺复兴音乐的国际化传播。", "cause": "谷登堡印刷革命的技术外溢，商业资本主义在欧洲城市的扩展", "figures": ["Johannes Gutenberg", "Ottaviano Petrucci"], "works": ["Harmonice Musices Odhecaton（1501）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/奥塔维亚诺·彼得鲁奇", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0013", "year": 1459, "yearEnd": 1521, "era": "renaissance", "region": ["FR", "IT", "NL"], "tags": ["佛兰德乐派", "复调", "世俗音乐"], "title": "若斯坎·德普雷：文艺复兴最伟大的作曲家", "body": "若斯坎·德普雷（Josquin des Prez）被同时代人和后人奉为文艺复兴最杰出的作曲家，其音乐将对位的复杂性与人文主义的情感表达完美结合。他的弥撒曲、经文歌与世俗歌曲（尚松）开创了将音乐与歌词情感密切结合的新风格，对后继者产生了决定性影响。", "cause": "意大利人文主义思潮对音乐情感表达的高度重视，以及各城邦宫廷对顶级音乐人才的竞争", "figures": ["Josquin des Prez"], "works": ["弥撒《武装的人》（Missa L'homme armé）", "经文歌《请怜悯我》（Miserere mei）", "《蟋蟀》（El Grillo）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/若斯坎·德普雷", "listen": "", "score": "https://imslp.org/wiki/Josquin_des_Prez"}, "importance": 3}, {"id": "ME-0058", "year": 1501, "yearEnd": null, "era": "renaissance", "region": ["IT"], "tags": ["乐谱印刷", "文艺复兴", "传播"], "title": "彼得鲁奇出版早期重要活字印刷乐谱", "body": "奥塔维亚诺·彼得鲁奇于 1501 年在威尼斯出版《和声百曲集》，通常被视为欧洲早期最重要的多声部活字印刷乐谱之一。它显著提升了乐谱复制与传播效率，加速了文艺复兴音乐在各地宫廷、教会与城市中的流通。", "cause": "印刷技术成熟后，音乐出版开始从手抄文化转向更大规模的商业复制。", "figures": ["Ottaviano Petrucci"], "works": ["《和声百曲集》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/奥塔维亚诺·彼得鲁奇", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0014", "year": 1517, "yearEnd": null, "era": "renaissance", "region": ["DE"], "tags": ["宗教改革", "众赞歌", "新教音乐"], "title": "路德宗教改革：众赞歌与会众参与音乐", "body": "马丁·路德于1517年发起宗教改革，他本人也是音乐爱好者，力主以德语众赞歌（Chorale）取代拉丁文圣咏，让会众直接参与礼拜歌唱。路德改革催生了大量德语宗教歌曲，直接影响了此后两个世纪的德国音乐传统，包括巴赫的大量创作。", "cause": "对罗马教会腐败的强烈批判，以及人文主义对以本国语言传播信仰的重视", "figures": ["Martin Luther", "Johann Walter"], "works": ["《上帝是我们坚固的保障》（Ein feste Burg）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/马丁·路德与音乐", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0015", "year": 1525, "yearEnd": 1594, "era": "renaissance", "region": ["IT", "VA"], "tags": ["复调", "弥撒曲", "宗教音乐"], "title": "帕莱斯特里纳：天主教复调圣乐的顶峰", "body": "罗马作曲家乔万尼·皮耶路易吉·达·帕莱斯特里纳（Giovanni Pierluigi da Palestrina）是天主教反宗教改革的音乐代言人。他的多声部复调弥撒曲和经文歌以声部的清晰、和声的纯净著称，达到文艺复兴复调声乐的最高峰，其《玛尔切鲁斯教皇弥撒》被奉为神圣复调音乐的典范。", "cause": "特伦特公会议（1545-1563）对教会音乐的清洗与整顿，要求歌词清晰可辨", "figures": ["Giovanni Pierluigi da Palestrina"], "works": ["玛尔切鲁斯教皇弥撒（Missa Papae Marcelli）", "《圣母哀歌》（Stabat Mater）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/乔瓦尼·皮耶路易吉·达·帕莱斯特里纳", "listen": "", "score": "https://imslp.org/wiki/Giovanni_Pierluigi_da_Palestrina"}, "importance": 3}, {"id": "ME-0072", "year": 1536, "yearEnd": null, "era": "renaissance", "region": ["ES"], "tags": ["器乐", "西班牙音乐", "维乌埃拉"], "title": "西班牙维乌埃拉曲集推动文艺复兴器乐写作", "body": "16 世纪西班牙的维乌埃拉曲集出版，标志着拨弦器乐独奏 repertory 的成熟。路易斯·米兰等人的作品将复调思维、舞曲写作与改编传统结合起来，推动了器乐音乐从“依附声乐”走向更独立的创作实践。", "cause": "伊比利亚半岛宫廷文化与印刷出版共同促进了器乐作品的保存、传播与演奏标准化。", "figures": ["Luis Milán"], "works": ["《宫廷音乐家》"], "links": {"wiki": "https://en.wikipedia.org/wiki/Luis_Mil%C3%A1n", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0016", "year": 1543, "yearEnd": null, "era": "renaissance", "region": ["IT"], "tags": ["鲁特琴", "器乐", "世俗音乐"], "title": "鲁特琴音乐与器乐独立发展", "body": "16世纪中期，鲁特琴（Lute）成为欧洲最流行的独奏乐器，器乐出版物大量涌现，器乐音乐开始从声乐的附庸中独立出来。意大利的里切尔卡（Ricercare）和法国的幻想曲（Fantaisie）是最早的重要纯器乐体裁，为巴洛克器乐的繁荣奠定了基础。", "cause": "乐谱印刷业的成熟使器乐曲得以广泛流传，宫廷娱乐与私人音乐活动的兴盛推动了对器乐的需求", "figures": ["Francesco da Milano", "Adrian Willaert"], "works": ["鲁特琴幻想曲集"], "links": {"wiki": "https://zh.wikipedia.org/wiki/鲁特琴", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0073", "year": 1550, "yearEnd": null, "era": "renaissance", "region": ["IT"], "tags": ["世俗声乐", "意大利", "牧歌"], "title": "意大利牧歌在 16 世纪中叶走向成熟", "body": "16 世纪中叶，意大利牧歌成为最具代表性的世俗声乐体裁之一。作曲家借助精细的文本绘景、复杂复调和情感刻画，将诗歌与音乐紧密结合，深刻影响了后来的歌剧、独唱歌曲与戏剧性声乐写作。", "cause": "人文主义文学繁荣与城市宫廷文化赞助，使高水平的世俗诗歌谱曲需求迅速增长。", "figures": ["Adrian Willaert", "Cipriano de Rore"], "works": ["意大利牧歌"], "links": {"wiki": "https://zh.wikipedia.org/wiki/牧歌_(音乐)", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0059", "year": 1562, "yearEnd": 1563, "era": "renaissance", "region": ["VA", "IT"], "tags": ["宗教改革", "教会音乐", "反宗教改革"], "title": "特伦托会议推动天主教礼仪音乐整顿", "body": "特伦托会议期间，天主教会针对礼仪实践展开全面整顿，音乐清晰度与文本可懂度成为核心议题。围绕复调是否妨碍经文理解的讨论，促成了后世以帕莱斯特里那为代表的“清晰、庄重、可辨词”的教会音乐范式。", "cause": "宗教改革冲击下，天主教会试图在教义、礼仪与艺术层面重新确立秩序与权威。", "figures": ["Giovanni Pierluigi da Palestrina"], "works": ["《马尔切卢斯教皇弥撒》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/特伦托会议", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0017", "year": 1567, "yearEnd": 1643, "era": "renaissance", "region": ["IT"], "tags": ["牧歌", "情感表达", "文艺复兴晚期"], "title": "蒙特威尔第：文艺复兴晚期牧歌与歌剧先驱", "body": "克劳迪奥·蒙特威尔第（Claudio Monteverdi）的前五卷牧歌代表文艺复兴晚期最后的辉煌。他大胆运用不协和音与半音化，强调歌词情感的音乐表达，将这种风格称为\"第二常规\"（Seconda prattica）。1607年他创作的歌剧《奥菲欧》标志着新的巴洛克时代的开始。", "cause": "佛罗伦萨卡梅拉塔学者圈对复兴古希腊戏剧音乐传统的强烈兴趣，以及宫廷庆典对综合性音乐戏剧的需求", "figures": ["Claudio Monteverdi"], "works": ["牧歌集（第一至五卷）", "《奥菲欧》（L'Orfeo，1607）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/克劳迪奥·蒙特威尔第", "listen": "", "score": "https://imslp.org/wiki/Claudio_Monteverdi"}, "importance": 3}, {"id": "ME-0018", "year": 1570, "yearEnd": 1590, "era": "renaissance", "region": ["IT"], "tags": ["歌剧起源", "佛罗伦萨卡梅拉塔", "单声部歌曲"], "title": "佛罗伦萨卡梅拉塔：歌剧诞生前夜", "body": "以温琴佐·伽利莱伊（伽利略之父）和朱利奥·卡奇尼为核心的佛罗伦萨卡梅拉塔学者圈，试图复兴古希腊戏剧音乐，创造出强调旋律与歌词情感表达的单声部歌曲风格（monody），即\"代表性风格\"（stile rappresentativo）。其成果直接催生了1600年前后世界上第一批歌剧。", "cause": "人文主义学者对古希腊戏剧中音乐力量的崇拜，以及对当时复调音乐\"败坏\"歌词清晰性的不满", "figures": ["Vincenzo Galilei", "Giulio Caccini", "Jacopo Peri"], "works": ["《尤丽迪茜》（Euridice，1600）", "《新音乐》（Le Nuove Musiche，1602）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/佛罗伦萨卡梅拉塔", "listen": "", "score": ""}, "importance": 3}]}, "era_03_baroque.json": {"meta": {"period": "baroque", "label": "巴洛克", "range": [1600, 1749], "version": "1.0", "updated": "2026-04-13"}, "events": [{"id": "ME-0019", "year": 1600, "yearEnd": null, "era": "baroque", "region": ["IT"], "tags": ["歌剧", "体裁创新", "戏剧"], "title": "歌剧诞生：《尤丽迪茜》首演", "body": "1600年10月，雅各波·佩里（Jacopo Peri）创作的《尤丽迪茜》在佛罗伦萨美第奇宫廷首演，被视为有完整乐谱留存的最早歌剧。歌剧综合了音乐、诗歌、舞蹈与舞台布景，成为巴洛克时期最重要的音乐体裁，并最终成为西方音乐最具影响力的艺术形式。", "cause": "佛罗伦萨贵族玛丽·德·美第奇与法国国王亨利四世的婚礼庆典，以及卡梅拉塔学者的多年理论积累", "figures": ["Jacopo Peri", "Giulio Caccini"], "works": ["《尤丽迪茜》（Euridice）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/歌剧", "listen": "", "score": "https://imslp.org/wiki/Euridice_(Peri,_Jacopo)"}, "importance": 3}, {"id": "ME-0020", "year": 1607, "yearEnd": null, "era": "baroque", "region": ["IT"], "tags": ["歌剧", "蒙特威尔第", "奥菲欧"], "title": "蒙特威尔第《奥菲欧》：早期歌剧的里程碑", "body": "克劳迪奥·蒙特威尔第为曼图瓦宫廷创作的歌剧《奥菲欧》（L'Orfeo）在艺术成就上远超早期歌剧，是西方音乐史上第一部真正意义上的伟大歌剧。其管弦乐配器丰富，戏剧表现力强大，将神话题材的情感悲剧推向新高度，确立了歌剧作为严肃艺术的地位。", "cause": "曼图瓦公爵弗朗切斯科·冈萨加委约创作，为宫廷狂欢节庆典准备", "figures": ["Claudio Monteverdi"], "works": ["《奥菲欧》（L'Orfeo）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/奥菲欧_(蒙特威尔第)", "listen": "https://www.youtube.com/results?search_query=Monteverdi+L'Orfeo", "score": "https://imslp.org/wiki/L'Orfeo_(Monteverdi,_Claudio)"}, "importance": 3}, {"id": "ME-0021", "year": 1637, "yearEnd": null, "era": "baroque", "region": ["IT"], "tags": ["歌剧院", "公众演出", "威尼斯"], "title": "威尼斯开设世界第一座公共歌剧院", "body": "威尼斯的圣卡西亚诺剧院（Teatro San Cassiano）于1637年向公众售票开放，成为世界上第一座商业歌剧院。此前歌剧仅在贵族宫廷内演出，公共歌剧院的出现使歌剧走向大众，催生了以娱乐性见长的威尼斯歌剧传统，深刻改变了音乐的社会功能与产业模式。", "cause": "威尼斯共和国发达的商业经济与市民文化，以及贵族家族对歌剧院商业潜力的看好", "figures": ["Benedetto Ferrari"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/威尼斯歌剧", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0022", "year": 1653, "yearEnd": 1713, "era": "baroque", "region": ["IT"], "tags": ["协奏曲", "奏鸣曲", "小提琴"], "title": "科雷利确立巴洛克器乐奏鸣曲范式", "body": "意大利作曲家阿尔坎杰洛·科雷利（Arcangelo Corelli）系统确立了教堂奏鸣曲（sonata da chiesa）和室内奏鸣曲（sonata da camera）的体裁规范，以及三重奏鸣曲的写作模式，并将小提琴演奏技术提升到新高度。其弦乐合奏协奏曲作品集奠定了大协奏曲（Concerto grosso）的范式。", "cause": "罗马宫廷与教会对器乐音乐的赞助热情，以及意大利小提琴制作工艺（斯特拉迪瓦里等）的飞速进步", "figures": ["Arcangelo Corelli"], "works": ["12首小提琴奏鸣曲 Op.5", "12首大协奏曲 Op.6"], "links": {"wiki": "https://zh.wikipedia.org/wiki/阿卡安基罗·科雷利", "listen": "", "score": "https://imslp.org/wiki/Arcangelo_Corelli"}, "importance": 2}, {"id": "ME-0023", "year": 1678, "yearEnd": 1741, "era": "baroque", "region": ["IT"], "tags": ["协奏曲", "小提琴", "标题音乐"], "title": "维瓦尔第：协奏曲形式的集大成者", "body": "安东尼奥·维瓦尔第（Antonio Vivaldi）一生创作了约500首协奏曲，其中小提琴协奏曲《四季》（Le quattro stagioni，1725）是历史上最著名的标题音乐之一。他确立了快-慢-快三乐章独奏协奏曲的标准形式，这一结构影响了莫扎特、贝多芬直至今日。", "cause": "威尼斯孤儿院（Ospedale della Pietà）对优质音乐教学与演出的稳定需求，以及意大利歌剧和器乐的全欧洲传播", "figures": ["Antonio Vivaldi"], "works": ["《四季》（Le quattro stagioni）", "《和谐的灵感》协奏曲集 Op.3"], "links": {"wiki": "https://zh.wikipedia.org/wiki/安东尼奥·维瓦尔第", "listen": "https://www.youtube.com/results?search_query=Vivaldi+Four+Seasons", "score": "https://imslp.org/wiki/Antonio_Vivaldi"}, "importance": 3}, {"id": "ME-0060", "year": 1678, "yearEnd": 1713, "era": "baroque", "region": ["IT"], "tags": ["协奏曲", "器乐", "巴洛克"], "title": "科雷利确立大协奏曲与小提琴写作典范", "body": "阿尔坎杰洛·科雷利以三重奏鸣曲和大协奏曲写作闻名，其清晰的和声组织、弓法处理与乐队分组方式，为巴洛克器乐风格提供了稳定范式。科雷利的作品广泛传播，对 18 世纪欧洲器乐写作产生持续影响。", "cause": "意大利城市与贵族赞助体系支持了职业器乐演奏家和出版市场的发展。", "figures": ["Arcangelo Corelli"], "works": ["《大协奏曲，作品6》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/阿尔坎杰洛·科雷利", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0024", "year": 1685, "yearEnd": 1750, "era": "baroque", "region": ["DE"], "tags": ["复调", "对位法", "巴赫", "键盘音乐"], "title": "约翰·塞巴斯蒂安·巴赫：巴洛克音乐集大成者", "body": "巴赫出生于德国音乐世家，历任多地管风琴师与宫廷乐长，终以莱比锡圣托马斯教堂音乐总监身份度过后半生。他将巴洛克复调艺术推向绝对巅峰，两卷《平均律键盘曲集》被誉为钢琴家的\"旧约圣经\"，《赋格的艺术》是对位法的终极探索。他去世的1750年被约定俗成地定为巴洛克时代的终结。", "cause": "德国路德教会对教堂音乐的持续需求，以及巴赫家族深厚的音乐世家传统", "figures": ["Johann Sebastian Bach"], "works": ["《平均律键盘曲集》（BWV 846-893）", "《勃兰登堡协奏曲》（BWV 1046-1051）", "《马太受难曲》（BWV 244）", "《b小调弥撒》（BWV 232）", "《赋格的艺术》（BWV 1080）", "无伴奏小提琴奏鸣曲与组曲（BWV 1001-1006）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/约翰·塞巴斯蒂安·巴赫", "listen": "https://www.youtube.com/results?search_query=Bach+Brandenburg+Concertos", "score": "https://imslp.org/wiki/Johann_Sebastian_Bach"}, "importance": 3}, {"id": "ME-0025", "year": 1685, "yearEnd": 1759, "era": "baroque", "region": ["DE", "GB"], "tags": ["清唱剧", "歌剧", "亨德尔"], "title": "亨德尔：清唱剧的伟大开创者", "body": "格奥尔格·弗里德里希·亨德尔（George Frideric Handel）与巴赫同年生于德国，但游历甚广，最终定居英国。他早年以意大利歌剧著称，后转向英语清唱剧（Oratorio），其《弥赛亚》（Messiah，1741）是西方音乐史上演出次数最多的大型合唱作品之一。他代表了巴洛克音乐走向公众、走向宏大戏剧效果的另一方向。", "cause": "英国观众对意大利歌剧的冷淡，以及亨德尔对更宏大、更易被英国大众接受的英语宗教剧的商业探索", "figures": ["George Frideric Handel"], "works": ["《弥赛亚》（Messiah）", "《水上音乐》（Water Music）", "《皇家烟火》（Music for the Royal Fireworks）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/格奥尔格·弗里德里希·亨德尔", "listen": "https://www.youtube.com/results?search_query=Handel+Messiah+Hallelujah", "score": "https://imslp.org/wiki/George_Frideric_Handel"}, "importance": 3}, {"id": "ME-0074", "year": 1700, "yearEnd": null, "era": "baroque", "region": ["IT"], "tags": ["乐器史", "钢琴", "技术"], "title": "克里斯托福里发明早期钢琴", "body": "巴托洛梅奥·克里斯托福里在 18 世纪初制造出能够通过击弦实现强弱变化的键盘乐器，被后世视为钢琴的起点。相较羽管键琴，钢琴更适合动态层次与歌唱性表达，最终深刻改写了独奏、室内乐与协奏曲传统。", "cause": "键盘乐器制造持续改进，演奏者对力度控制与更丰富音响表现的需求不断上升。", "figures": ["Bartolomeo Cristofori"], "works": ["早期钢琴"], "links": {"wiki": "https://zh.wikipedia.org/wiki/巴托洛梅奥·克里斯托福里", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0075", "year": 1711, "yearEnd": null, "era": "baroque", "region": ["GB"], "tags": ["歌剧", "巴洛克", "亨德尔"], "title": "亨德尔《里纳尔多》推动意大利歌剧在伦敦传播", "body": "1711 年，亨德尔的《里纳尔多》在伦敦上演并取得成功，证明了意大利正歌剧在英国市场的巨大吸引力。它强化了歌剧明星制度、咏叹调中心结构与壮观舞台效果在欧洲都市文化中的影响。", "cause": "伦敦公共剧院与贵族赞助并存，为歌剧这种高成本综合艺术提供了稳定市场。", "figures": ["George Frideric Handel"], "works": ["《里纳尔多》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/里纳尔多", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0026", "year": 1722, "yearEnd": null, "era": "baroque", "region": ["FR"], "tags": ["和声理论", "调性", "理论"], "title": "拉莫出版《和声学》：功能和声体系的建立", "body": "法国作曲家让-菲利普·拉莫（Jean-Philippe Rameau）于1722年出版《和声学论》（Traité de l'harmonie），首次系统建立了以根音与转位概念为核心的大小调功能和声体系。这一理论成为西方古典音乐和声学的基础，影响延续至20世纪。", "cause": "巴洛克晚期音乐实践中大小调调性逐渐取代中古调式，迫切需要系统性的理论阐释", "figures": ["Jean-Philippe Rameau"], "works": ["《和声学论》（Traité de l'harmonie，1722）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/让-菲利普·拉莫", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0061", "year": 1725, "yearEnd": null, "era": "baroque", "region": ["IT"], "tags": ["协奏曲", "巴洛克", "标题音乐"], "title": "维瓦尔第《四季》成为协奏曲与标题音乐名作", "body": "维瓦尔第的《四季》通过独奏小提琴、乐队织体与配套十四行诗的结合，将自然景象、季节意象与器乐叙事结合起来。它既是巴洛克独奏协奏曲的代表作，也是欧洲标题音乐传统的重要先声。", "cause": "威尼斯公共音乐生活繁荣，独奏演奏技巧和器乐出版市场共同推动了协奏曲体裁的成熟。", "figures": ["Antonio Vivaldi"], "works": ["《四季》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/四季_(维瓦尔第)", "listen": "", "score": ""}, "importance": 2}]}, "era_04_classical_romantic.json": {"meta": {"period": "classical_romantic", "label": "古典主义与浪漫主义", "range": [1750, 1899], "version": "1.0", "updated": "2026-04-13"}, "events": [{"id": "ME-0027", "year": 1750, "yearEnd": 1820, "era": "classical", "region": ["AT", "DE"], "tags": ["古典主义", "交响曲", "奏鸣曲式"], "title": "古典主义时期：交响曲与奏鸣曲式的确立", "body": "1750年后西方音乐进入古典主义时期，以清晰、平衡、理性为美学核心，取代巴洛克的华丽复调。约瑟夫·海顿（Franz Joseph Haydn）系统确立了交响曲的四乐章结构和奏鸣曲式（Sonata form），并发展了弦乐四重奏体裁，被誉为\"交响曲之父\"和\"弦乐四重奏之父\"。器乐音乐在此时期首次超越声乐成为最受欢迎的音乐形式。", "cause": "启蒙运动的理性主义与人文主义思潮，市民阶级兴起带来的新音乐消费群体", "figures": ["Franz Joseph Haydn"], "works": ["第94号交响曲《惊愕》", "第104号交响曲《伦敦》", "弦乐四重奏《云雀》Op.64 No.5"], "links": {"wiki": "https://zh.wikipedia.org/wiki/约瑟夫·海顿", "listen": "https://www.youtube.com/results?search_query=Haydn+Symphony+94", "score": "https://imslp.org/wiki/Joseph_Haydn"}, "importance": 3}, {"id": "ME-0028", "year": 1756, "yearEnd": 1791, "era": "classical", "region": ["AT"], "tags": ["莫扎特", "协奏曲", "歌剧", "古典主义"], "title": "莫扎特：古典主义的全能天才", "body": "沃尔夫冈·阿马德乌斯·莫扎特（Wolfgang Amadeus Mozart）是西方音乐史上最伟大的天才之一，在短暂的35年生命中创作了600余部作品，涵盖所有主要体裁。他将古典主义的形式美与深刻的情感表达完美融合，其钢琴协奏曲确立了现代协奏曲范式，歌剧《费加罗的婚姻》《唐·乔凡尼》《魔笛》是歌剧史上不朽的杰作。", "cause": "萨尔茨堡宫廷与维也纳自由市场的音乐环境，以及莫扎特家庭自幼的严格专业训练", "figures": ["Wolfgang Amadeus Mozart"], "works": ["《费加罗的婚姻》（Le nozze di Figaro）", "《唐·乔凡尼》（Don Giovanni）", "《魔笛》（Die Zauberflöte）", "第41号交响曲《朱庇特》", "钢琴协奏曲第20号（KV 466）", "《安魂曲》（KV 626）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/沃尔夫冈·阿马德乌斯·莫扎特", "listen": "https://www.youtube.com/results?search_query=Mozart+Symphony+40", "score": "https://imslp.org/wiki/Wolfgang_Amadeus_Mozart"}, "importance": 3}, {"id": "ME-0062", "year": 1762, "yearEnd": null, "era": "classical", "region": ["AT", "IT"], "tags": ["歌剧改革", "古典主义", "格鲁克"], "title": "格鲁克推动歌剧改革", "body": "格鲁克在《奥菲欧与欧律狄刻》等作品中削弱炫技性装饰咏叹调的支配地位，强调剧情推进、戏剧统一和音乐服务于舞台行动。这一改革对后来的莫扎特、法语歌剧以及 19 世纪戏剧性歌剧写作产生重要影响。", "cause": "18 世纪中叶的歌剧实践过度依赖歌手炫技，导致剧情与音乐表达出现分裂。", "figures": ["Christoph Willibald Gluck"], "works": ["《奥菲欧与欧律狄刻》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/克里斯托夫·维利巴尔德·格鲁克", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0029", "year": 1770, "yearEnd": 1827, "era": "classical", "region": ["DE", "AT"], "tags": ["贝多芬", "交响曲", "英雄主义", "古典浪漫过渡"], "title": "贝多芬：横跨古典与浪漫的音乐革命者", "body": "路德维希·凡·贝多芬（Ludwig van Beethoven）承接海顿、莫扎特的古典主义传统，并以英雄主义风格将交响曲发展为前所未有的宏大规模。《第三交响曲\"英雄\"》（1804）彻底打破交响曲的时间与情感边界；《第九交响曲》（1824）在末乐章引入合唱，是音乐史上最重要的里程碑之一。晚期弦乐四重奏将器乐推向哲学冥想的高度，是古典向浪漫主义过渡的关键桥梁。", "cause": "法国大革命与拿破仑时代的英雄主义精神，以及贝多芬自身耳聋带来的内心挣扎与精神升华", "figures": ["Ludwig van Beethoven"], "works": ["第3交响曲《英雄》（Op.55）", "第5交响曲《命运》（Op.67）", "第9交响曲（Op.125）", "《月光奏鸣曲》（Op.27 No.2）", "小提琴协奏曲（Op.61）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/路德维希·凡·贝多芬", "listen": "https://www.youtube.com/results?search_query=Beethoven+Symphony+9", "score": "https://imslp.org/wiki/Ludwig_van_Beethoven"}, "importance": 3}, {"id": "ME-0076", "year": 1787, "yearEnd": null, "era": "classical", "region": ["CZ", "AT"], "tags": ["歌剧", "古典主义", "莫扎特"], "title": "莫扎特《唐璜》拓展歌剧人物心理与戏剧深度", "body": "《唐璜》将喜剧、悲剧、社会讽刺与复杂人物刻画融为一体，是古典时期歌剧艺术的高峰之一。莫扎特在其中展现了高度成熟的重唱组织、管弦乐色彩与角色心理书写能力。", "cause": "维也纳与布拉格的歌剧文化为作曲家提供了更成熟的公共剧院环境和观众基础。", "figures": ["Wolfgang Amadeus Mozart"], "works": ["《唐璜》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/唐·乔望尼", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0030", "year": 1797, "yearEnd": 1828, "era": "romantic", "region": ["AT"], "tags": ["舒伯特", "艺术歌曲", "浪漫主义"], "title": "舒伯特与德语艺术歌曲（Lied）的黄金时代", "body": "弗朗茨·舒伯特（Franz Schubert）在短暂的31年生命中创作了600余首艺术歌曲（Lied），将诗歌与音乐的结合提升至无与伦比的高度，开创了德语艺术歌曲的黄金传统。《冬之旅》《天鹅之歌》等声乐套曲是浪漫主义最深刻的内心独白，《未完成交响曲》以其独特的抒情性区别于贝多芬的英雄主义风格。", "cause": "德国浪漫主义文学运动（歌德、席勒诗歌）对音乐的强烈召唤，以及维也纳自由知识分子沙龙文化的滋养", "figures": ["Franz Schubert"], "works": ["《冬之旅》（Winterreise）", "《魔王》（Erlkönig）", "《未完成交响曲》（D.759）", "《鳟鱼五重奏》（D.667）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/弗朗茨·舒伯特", "listen": "https://www.youtube.com/results?search_query=Schubert+Winterreise", "score": "https://imslp.org/wiki/Franz_Schubert"}, "importance": 3}, {"id": "ME-0077", "year": 1808, "yearEnd": null, "era": "classical", "region": ["AT"], "tags": ["交响曲", "贝多芬", "音乐史"], "title": "1808 年《第五交响曲》与《第六交响曲》首演", "body": "1808 年 12 月，贝多芬在维也纳举行历史性音乐会，首演《第五交响曲》和《第六交响曲》等重要作品。该场音乐会集中展示了他在动机发展、戏剧张力与标题性表达方面的突破，是交响曲史上的标志性时刻。", "cause": "公共音乐会制度扩张，使大型交响作品能够面向更广泛城市听众而非仅依附宫廷。", "figures": ["Ludwig van Beethoven"], "works": ["《第五交响曲》", "《第六交响曲》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/贝多芬作品列表", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0032", "year": 1810, "yearEnd": 1849, "era": "romantic", "region": ["PL", "FR"], "tags": ["钢琴音乐", "肖邦", "民族主义"], "title": "肖邦：钢琴诗人与波兰民族音乐", "body": "弗里德里克·肖邦（Frédéric Chopin）几乎将全部创作集中于钢琴独奏曲，以玛祖卡、波洛奈兹、夜曲、练习曲、叙事曲等体裁将钢琴音乐提升至前所未有的诗意高度。他的音乐将波兰民族音乐元素融入浪漫主义语汇，是19世纪民族主义音乐思潮的重要先驱。", "cause": "波兰被列强瓜分的历史悲剧激发了强烈的民族情感，以及巴黎浪漫主义文学艺术圈的深刻影响", "figures": ["Frédéric Chopin"], "works": ["24首前奏曲（Op.28）", "《革命练习曲》（Op.10 No.12）", "《幻想即兴曲》（Op.66）", "波洛奈兹《英雄》（Op.53）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/弗里德里克·肖邦", "listen": "https://www.youtube.com/results?search_query=Chopin+Nocturne", "score": "https://imslp.org/wiki/Frédéric_Chopin"}, "importance": 3}, {"id": "ME-0033", "year": 1813, "yearEnd": 1883, "era": "romantic", "region": ["DE"], "tags": ["瓦格纳", "乐剧", "整体艺术作品", "歌剧改革"], "title": "瓦格纳：乐剧与\"整体艺术作品\"革命", "body": "理夏德·瓦格纳（Richard Wagner）以\"整体艺术作品\"（Gesamtkunstwerk）理论彻底革新了歌剧形式，将音乐、诗歌、戏剧、视觉艺术融为一体。他发展出\"主导动机\"（Leitmotiv）技法，以无终旋律打破传统分曲结构，《尼伯龙根的指环》四联剧是19世纪最宏大的音乐戏剧工程，为此他专门在拜罗伊特建造了自己的剧院。", "cause": "对当时意大利歌剧\"为歌手服务\"的数字型音乐的强烈不满，以及德国浪漫主义哲学（叔本华）对音乐精神地位的高度推崇", "figures": ["Richard Wagner"], "works": ["《尼伯龙根的指环》（Der Ring des Nibelungen）", "《特里斯坦与伊索尔德》（Tristan und Isolde）", "《帕西法尔》（Parsifal）", "《罗恩格林》（Lohengrin）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/理夏德·瓦格纳", "listen": "https://www.youtube.com/results?search_query=Wagner+Ride+of+Valkyries", "score": "https://imslp.org/wiki/Richard_Wagner"}, "importance": 3}, {"id": "ME-0031", "year": 1829, "yearEnd": null, "era": "romantic", "region": ["DE"], "tags": ["巴赫复兴", "历史主义", "孟德尔颂"], "title": "孟德尔颂指挥《马太受难曲》：巴赫复兴运动", "body": "1829年，年仅20岁的菲利克斯·孟德尔颂（Felix Mendelssohn）在柏林演唱学院指挥复演巴赫《马太受难曲》，是巴赫去世后该作品的首次公开演出。这一事件引发了席卷欧洲的\"巴赫复兴运动\"，使被遗忘逾半个世纪的巴赫重回音乐史的核心地位，同时开启了音乐史的\"历史主义\"传统。", "cause": "德国浪漫主义民族文化意识觉醒，以及孟德尔颂自幼在家中接触巴赫手稿的个人因缘", "figures": ["Felix Mendelssohn", "Johann Sebastian Bach"], "works": ["《马太受难曲》（BWV 244）复演"], "links": {"wiki": "https://zh.wikipedia.org/wiki/菲利克斯·门德尔松", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0063", "year": 1829, "yearEnd": null, "era": "romantic", "region": ["DE"], "tags": ["复兴", "巴赫", "浪漫主义"], "title": "门德尔松复排《马太受难曲》推动巴赫复兴", "body": "1829 年，门德尔松指挥演出巴赫《马太受难曲》，引发 19 世纪对巴赫作品与更早音乐传统的重新评价。这不仅是作曲家声誉的复兴，也标志着现代意义上“历史音乐会”与经典曲目观念的形成。", "cause": "浪漫主义时代兴起历史意识，音乐界开始主动回望并重建早期音乐遗产。", "figures": ["Felix Mendelssohn", "Johann Sebastian Bach"], "works": ["《马太受难曲》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/马太受难曲", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0078", "year": 1830, "yearEnd": null, "era": "romantic", "region": ["FR"], "tags": ["标题交响曲", "浪漫主义", "柏辽兹"], "title": "柏辽兹《幻想交响曲》树立标题交响曲典范", "body": "《幻想交响曲》以连贯的故事构想、固定乐思与极具戏剧性的管弦乐法，成为浪漫主义标题交响曲的代表作。作品拓展了交响乐的叙事潜力，对李斯特、瓦格纳及后来的交响诗传统影响深远。", "cause": "浪漫主义审美强调主观情感、文学想象与个体经验，为交响乐叙事化提供了思想土壤。", "figures": ["Hector Berlioz"], "works": ["《幻想交响曲》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/幻想交响曲", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0034", "year": 1840, "yearEnd": 1893, "era": "romantic", "region": ["RU"], "tags": ["民族乐派", "柴可夫斯基", "芭蕾舞", "俄罗斯音乐"], "title": "柴可夫斯基与俄罗斯民族音乐的国际化", "body": "彼得·伊里奇·柴可夫斯基（Pyotr Ilyich Tchaikovsky）是俄罗斯音乐走向世界的最重要使者。他以西欧浪漫主义技法融合俄罗斯民族音乐元素，创作了《天鹅湖》《胡桃夹子》《睡美人》三大芭蕾舞剧，以及《第一钢琴协奏曲》《小提琴协奏曲》等不朽名作，使俄罗斯音乐在国际上赢得崇高地位。", "cause": "19世纪俄罗斯民族文化意识的觉醒，以及圣彼得堡帝国芭蕾舞团与音乐学院的强大制度支持", "figures": ["Pyotr Ilyich Tchaikovsky"], "works": ["《天鹅湖》（Swan Lake）", "《胡桃夹子》（The Nutcracker）", "第1钢琴协奏曲（Op.23）", "《1812序曲》（Op.49）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/彼得·伊里奇·柴可夫斯基", "listen": "https://www.youtube.com/results?search_query=Tchaikovsky+Swan+Lake", "score": "https://imslp.org/wiki/Pyotr_Ilyich_Tchaikovsky"}, "importance": 3}, {"id": "ME-0079", "year": 1876, "yearEnd": null, "era": "romantic", "region": ["DE"], "tags": ["歌剧节", "瓦格纳", "音乐戏剧"], "title": "拜罗伊特音乐节确立瓦格纳音乐戏剧中心地位", "body": "1876 年首届拜罗伊特音乐节上演《尼伯龙根的指环》全剧，象征瓦格纳音乐戏剧理想以专门剧院与节庆制度的形式落地。它深刻影响了现代歌剧制作、导演观念与剧院建筑。", "cause": "瓦格纳追求“整体艺术作品”理念，需要不同于常规剧院的空间与演出组织方式。", "figures": ["Richard Wagner"], "works": ["《尼伯龙根的指环》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/拜罗伊特音乐节", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0035", "year": 1883, "yearEnd": null, "era": "romantic", "region": ["US"], "tags": ["技术革新", "录音", "爱迪生"], "title": "爱迪生发明留声机：录音技术改变音乐传播", "body": "托马斯·爱迪生于1877年发明留声机（phonograph），1883年后商业化留声机开始普及。录音技术的出现彻底改变了音乐的传播方式：音乐首次可以被保存、复制和跨越时空传播，为20世纪唱片工业的诞生奠定了基础，也深刻改变了人类与音乐的关系。", "cause": "工业革命后技术进步的惯性，以及爱迪生对实用技术发明的系统性探索", "figures": ["Thomas Edison"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/留声机", "listen": "", "score": ""}, "importance": 3}]}, "era_05_modern.json": {"meta": {"period": "modern", "label": "现代音乐", "range": [1900, 1969], "version": "1.0", "updated": "2026-04-13"}, "events": [{"id": "ME-0036", "year": 1894, "yearEnd": 1918, "era": "modern", "region": ["FR"], "tags": ["印象主义", "德彪西", "调性拓展"], "title": "德彪西与印象主义音乐：调性的溶解", "body": "克劳德·德彪西（Claude Debussy）以全音音阶、平行和声和模糊调性创造出\"印象主义\"音乐风格，用声音描绘光影、自然与瞬间感受。《牧神午后前奏曲》（1894）标志着20世纪音乐新时代的开端，《月光》《水中倒影》等钢琴曲彻底改变了和声的功能逻辑，是打破调性束缚的重要先驱。", "cause": "印象主义绘画（莫奈、雷诺阿）和象征主义文学对音乐的强烈影响，以及德彪西在1889年巴黎世博会上接触到东南亚甘美兰音乐的震撼", "figures": ["Claude Debussy"], "works": ["《牧神午后前奏曲》（Prélude à l'après-midi d'un faune）", "《海》（La Mer）", "《意象集》（Images）", "《月光》（Clair de lune）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/克劳德·德彪西", "listen": "https://www.youtube.com/results?search_query=Debussy+Clair+de+lune", "score": "https://imslp.org/wiki/Claude_Debussy"}, "importance": 3}, {"id": "ME-0039", "year": 1900, "yearEnd": 1930, "era": "modern", "region": ["US"], "tags": ["爵士乐", "布鲁斯", "新奥尔良", "非裔美国人"], "title": "爵士乐诞生：新奥尔良的音乐革命", "body": "20世纪初，爵士乐在美国南部港口城市新奥尔良诞生，融合了非洲裔美国人的布鲁斯（Blues）传统、拉格泰姆（Ragtime）的切分节奏与欧洲和声，以即兴演奏为核心特征。路易斯·阿姆斯特朗（Louis Armstrong）成为第一位获得国际认可的爵士大师，将爵士乐从街头推向音乐厅。爵士乐是美国对20世纪文化最重要的贡献之一。", "cause": "非裔美国人奴隶解放后在南方的音乐文化积累，新奥尔良独特的法语-西班牙-非洲多元文化交融，以及黑人葬礼铜管乐队传统", "figures": ["Louis Armstrong", "Jelly Roll Morton", "King Oliver"], "works": ["《圣路易斯布鲁斯》", "《西端布鲁斯》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/爵士乐", "listen": "https://www.youtube.com/results?search_query=Louis+Armstrong+jazz", "score": ""}, "importance": 3}, {"id": "ME-0037", "year": 1913, "yearEnd": null, "era": "modern", "region": ["FR", "RU"], "tags": ["现代主义", "斯特拉文斯基", "节奏", "芭蕾"], "title": "《春之祭》首演骚乱：现代音乐的宣言", "body": "1913年5月29日，伊戈尔·斯特拉文斯基（Igor Stravinsky）为佳吉列夫俄罗斯芭蕾舞团创作的《春之祭》（Le Sacre du printemps）在巴黎香榭丽舍剧院首演，以激进的节奏、不协和和声与原始主义风格引发观众骚乱。这次首演被视为20世纪音乐最重要的历史事件，彻底宣告了现代主义音乐的到来。", "cause": "佳吉列夫对前卫艺术的强烈追求，以及斯特拉文斯基对原始主义与俄罗斯民间音乐的独特诠释", "figures": ["Igor Stravinsky", "Sergei Diaghilev", "Vaslav Nijinsky"], "works": ["《春之祭》（Le Sacre du printemps）", "《火鸟》（The Firebird）", "《彼得鲁什卡》（Petrushka）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/春之祭", "listen": "https://www.youtube.com/results?search_query=Stravinsky+Rite+of+Spring", "score": "https://imslp.org/wiki/The_Rite_of_Spring_(Stravinsky,_Igor)"}, "importance": 3}, {"id": "ME-0080", "year": 1917, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["爵士", "录音工业", "美国"], "title": "首张商业爵士唱片问世", "body": "1917 年，Original Dixieland Jass Band 录制并发行《Livery Stable Blues》，通常被视为首张商业发行的爵士唱片。虽然其风格与后世爵士观念并不完全相同，但它标志着爵士乐开始进入唱片工业与大众市场。", "cause": "录音产业发展使地方音乐风格能够突破现场演出限制，快速向全国乃至跨国传播。", "figures": ["Original Dixieland Jass Band"], "works": ["《Livery Stable Blues》"], "links": {"wiki": "https://en.wikipedia.org/wiki/Original_Dixieland_Jass_Band", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0038", "year": 1921, "yearEnd": null, "era": "modern", "region": ["AT", "DE"], "tags": ["十二音技法", "勋伯格", "无调性", "序列主义"], "title": "勋伯格发明十二音技法：调性的彻底颠覆", "body": "阿诺德·勋伯格（Arnold Schoenberg）于1921年正式发展出十二音技法（twelve-tone technique），将一个八度内的十二个半音以预先设定的序列（音列）组织音乐，彻底摒弃调性功能关系。这一技法开创了序列主义（Serialism）音乐流派，深刻影响了整个20世纪的学院派作曲，是西方音乐史上最激进的革命之一。", "cause": "浪漫晚期（瓦格纳、马勒）半音化和声对调性的极度拉伸，以及勋伯格对新的系统性结构原则的迫切探索", "figures": ["Arnold Schoenberg", "Alban Berg", "Anton Webern"], "works": ["钢琴组曲 Op.25（首批十二音作品）", "小提琴协奏曲 Op.36"], "links": {"wiki": "https://zh.wikipedia.org/wiki/十二音技法", "listen": "", "score": "https://imslp.org/wiki/Arnold_Schoenberg"}, "importance": 3}, {"id": "ME-0040", "year": 1924, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["爵士乐", "交响乐", "盖希文", "融合"], "title": "《蓝色狂想曲》首演：爵士与古典的历史性融合", "body": "乔治·盖希文（George Gershwin）创作的《蓝色狂想曲》（Rhapsody in Blue）于1924年2月12日首演，由保罗·怀特曼乐队在纽约卡内基音乐厅演出。这部作品将爵士乐语汇带入交响音乐厅，是第一部被主流社会广泛接受的爵士交响乐作品，标志着爵士乐进入严肃音乐领域的重大突破。", "cause": "爵士乐在20年代的迅速崛起，以及白人主流社会对黑人爵士文化的保留态度——保罗·怀特曼希望以更\"体面\"的方式向上层阶级推介爵士乐", "figures": ["George Gershwin", "Paul Whiteman"], "works": ["《蓝色狂想曲》（Rhapsody in Blue）", "《波吉与贝丝》（Porgy and Bess）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/蓝色狂想曲", "listen": "https://www.youtube.com/results?search_query=Gershwin+Rhapsody+in+Blue", "score": "https://imslp.org/wiki/Rhapsody_in_Blue_(Gershwin,_George)"}, "importance": 3}, {"id": "ME-0041", "year": 1930, "yearEnd": 1945, "era": "modern", "region": ["US"], "tags": ["摇摆乐", "大乐队", "爵士乐"], "title": "摇摆乐时代：爵士乐进入美国主流文化", "body": "20世纪30年代，以本尼·古德曼（Benny Goodman）、杜克·艾灵顿（Duke Ellington）、格伦·米勒（Glenn Miller）为代表的大乐队（Big Band）演奏的摇摆乐（Swing）风靡全美，爵士乐正式进入美国主流大众文化。1938年古德曼在卡内基音乐厅的演出是爵士乐历史上具有里程碑意义的时刻。", "cause": "大萧条后美国民众对轻松娱乐的强烈需求，以及无线电广播的普及使爵士乐得以全国传播", "figures": ["Benny Goodman", "Duke Ellington", "Glenn Miller", "Count Basie"], "works": ["《A字列车》（Take the A Train）", "《月光曲》（Moonlight Serenade）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/大乐队", "listen": "https://www.youtube.com/results?search_query=Duke+Ellington+Take+the+A+Train", "score": ""}, "importance": 2}, {"id": "ME-0081", "year": 1931, "yearEnd": null, "era": "modern", "region": ["IN"], "tags": ["印度电影音乐", "有声电影", "南亚"], "title": "《阿拉姆·阿拉》开启印度有声电影音乐时代", "body": "1931 年上映的《阿拉姆·阿拉》通常被视为印度第一部有声长片。影片中大量歌曲的成功，奠定了印度电影音乐与叙事深度结合的工业模式，之后歌曲与配乐成为印度流行音乐传播的核心渠道之一。", "cause": "电影技术升级与城市娱乐产业扩张，使电影迅速成为汇聚戏剧、歌曲和明星文化的大众媒介。", "figures": ["Ardeshir Irani"], "works": ["《阿拉姆·阿拉》"], "links": {"wiki": "https://en.wikipedia.org/wiki/Alam_Ara", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0064", "year": 1945, "yearEnd": 1950, "era": "modern", "region": ["US"], "tags": ["爵士", "现代主义", "比波普"], "title": "比波普确立现代爵士语言", "body": "20 世纪 40 年代中后期，查理·帕克、迪齐·吉莱斯皮等人推动比波普形成。高速旋律、复杂和声替代与小编制即兴演奏，使爵士从舞厅娱乐进一步转向高度艺术化、技术化的现代音乐语言。", "cause": "大乐队时代商业化日益成熟，年轻乐手转而追求更复杂、更具个人表达空间的小型编制。", "figures": ["Charlie Parker", "Dizzy Gillespie", "Thelonious Monk"], "works": ["《Ko-Ko》", "《A Night in Tunisia》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/咆勃爵士", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0042", "year": 1948, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["技术革新", "LP唱片", "录音工业"], "title": "LP密纹唱片发明：录音工业的重大革命", "body": "哥伦比亚唱片公司于1948年推出33⅓转长时间密纹唱片（LP，Long Play），将单面播放时间从4分钟延长至约22分钟。LP使交响曲、歌剧等大型作品得以完整录制，深刻改变了音乐的消费方式，催生了\"专辑\"（Album）文化，并为20世纪后半叶的摇滚乐时代奠定了媒介基础。", "cause": "二战后美国消费社会的高速发展，以及哥伦比亚唱片工程师彼得·戈尔德马克（Peter Goldmark）的技术突破", "figures": ["Peter Goldmark"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/黑胶唱片", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0065", "year": 1948, "yearEnd": null, "era": "modern", "region": ["FR"], "tags": ["电子音乐", "录音技术", "法国"], "title": "舍费尔提出“具体音乐”观念", "body": "1948 年，皮埃尔·舍费尔以唱片与录音设备剪接、变速和拼贴现实声音材料，提出“具体音乐”（musique concrète）观念。它将录音本身变成作曲媒介，是电子音乐、声响艺术与后来的采样文化的重要起点。", "cause": "广播技术和录音技术的发展，使作曲不再完全依赖乐谱与传统乐器。", "figures": ["Pierre Schaeffer"], "works": ["《五首噪音练习曲》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/具象音乐", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0082", "year": 1948, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["录音工业", "唱片", "技术媒介"], "title": "LP 唱片推动专辑时代成熟", "body": "1948 年，哥伦比亚公司推出 33 1/3 转微纹长时唱片（LP）。更长的播放时长改变了音乐发行与聆听方式，使“专辑”成为比单曲更稳定的艺术与商业单位，并深刻影响古典、爵士与流行音乐的制作结构。", "cause": "录音工业寻求更高保真度与更长播放时长，以满足家庭聆听和作品完整呈现需求。", "figures": ["Columbia Records"], "works": ["LP（Long Play）唱片"], "links": {"wiki": "https://zh.wikipedia.org/wiki/LP唱片", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0044", "year": 1952, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["前卫音乐", "偶然音乐", "实验音乐"], "title": "约翰·凯奇《4分33秒》：沉默作为音乐", "body": "美国前卫作曲家约翰·凯奇（John Cage）于1952年创作《4分33秒》——演奏者在钢琴前静坐4分33秒不发出任何乐音，将环境声音作为音乐本身。这件作品彻底颠覆了\"音乐\"的定义，是20世纪先锋艺术最著名也最具争议的宣言，影响涵盖音乐、行为艺术乃至哲学领域。", "cause": "受禅宗思想与达达主义艺术启发，凯奇对西方音乐中作曲家意图的权威性提出根本性质疑", "figures": ["John Cage"], "works": ["《4分33秒》（4'33\"）", "《变化的音乐》（Music of Changes）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/4分33秒", "listen": "https://www.youtube.com/results?search_query=John+Cage+4+33", "score": ""}, "importance": 3}, {"id": "ME-0043", "year": 1955, "yearEnd": 1970, "era": "modern", "region": ["US", "GB"], "tags": ["摇滚乐", "电吉他", "青年文化"], "title": "摇滚乐诞生：青年反叛文化的音乐革命", "body": "20世纪50年代，摇滚乐（Rock and Roll）从布鲁斯与节奏布鲁斯（R&B）中诞生，以埃尔维斯·普雷斯利（Elvis Presley）为标志性人物走红全美。60年代披头士乐队（The Beatles）引领\"英国入侵\"，鲍勃·迪伦以歌词承载社会批判，伍德斯托克音乐节（1969）成为整整一代人的精神图腾。摇滚乐成为20世纪最具影响力的大众音乐形式。", "cause": "战后婴儿潮催生庞大青年消费群体，冷战时代年轻人对权威的反叛，电吉他与电放大技术的成熟，黑人音乐文化向白人主流市场的突破", "figures": ["Elvis Presley", "Chuck Berry", "The Beatles", "Bob Dylan", "Jimi Hendrix"], "works": ["《约翰尼·B·古德》（Johnny B. Goode）", "《想牵你的手》（I Want to Hold Your Hand）", "《随风飘散》（Blowin' in the Wind）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/摇滚乐", "listen": "https://www.youtube.com/results?search_query=Elvis+Presley+Hound+Dog", "score": ""}, "importance": 3}, {"id": "ME-0083", "year": 1958, "yearEnd": null, "era": "modern", "region": ["BR"], "tags": ["拉美音乐", "巴西", "波萨诺瓦"], "title": "《Chega de Saudade》标志波萨诺瓦兴起", "body": "若昂·吉尔伯托录制的《Chega de Saudade》通常被视为波萨诺瓦风格成型的重要标志。它以更轻柔的节奏处理、细腻和声与亲密化演唱，重塑了巴西城市流行音乐，并很快对全球爵士与流行音乐产生影响。", "cause": "巴西都市中产文化、桑巴传统与现代和声语言相结合，催生出更内省细腻的新型歌曲风格。", "figures": ["João Gilberto", "Antônio Carlos Jobim"], "works": ["《Chega de Saudade》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/波萨诺瓦", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0045", "year": 1964, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["合成器", "电子音乐", "技术革新"], "title": "Moog合成器商业化：电子音乐进入大众", "body": "罗伯特·莫格（Robert Moog）于1964年发布第一台商业化Moog合成器，将电子音色与键盘演奏结合，开创了合成器音乐的新时代。60年代末温蒂·卡洛斯（Wendy Carlos）的专辑《巴赫切换》（Switched-On Bach，1968）证明合成器可以演奏严肃音乐，合成器随后迅速成为流行乐、摇滚乐与电子音乐的核心乐器。", "cause": "晶体管与电路技术进步使电子乐器小型化成为可能，以及实验音乐家对新音色的持续探索", "figures": ["Robert Moog", "Wendy Carlos"], "works": ["《巴赫切换》（Switched-On Bach，1968）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/莫格合成器", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0084", "year": 1968, "yearEnd": null, "era": "modern", "region": ["US"], "tags": ["电子音乐", "合成器", "录音工业"], "title": "《Switched-On Bach》证明合成器可进入主流音乐市场", "body": "温迪·卡洛斯的专辑《Switched-On Bach》用 Moog 合成器演奏巴赫作品，向大众证明电子音色不仅适用于实验音乐，也能进入高销量录音市场。它大幅提升了合成器的可见度，对流行、电影和电子音乐制作影响深远。", "cause": "合成器商业化后，市场需要具有示范性的作品来证明其艺术性与可传播性。", "figures": ["Wendy Carlos", "Robert Moog"], "works": ["《Switched-On Bach》"], "links": {"wiki": "https://en.wikipedia.org/wiki/Switched-On_Bach", "listen": "", "score": ""}, "importance": 3}]}, "era_06_contemporary.json": {"meta": {"period": "contemporary", "label": "当代音乐", "range": [1970, 2030], "version": "1.0", "updated": "2026-04-13"}, "events": [{"id": "ME-0046", "year": 1970, "yearEnd": 1979, "era": "contemporary", "region": ["DE"], "tags": ["电子音乐", "克拉夫特维克", "合成器", "流行"], "title": "克拉夫特维克：电子流行音乐的开山之作", "body": "德国乐队克拉夫特维克（Kraftwerk）于70年代以纯电子乐器创作出极简主义的机械美学音乐，专辑《Autobahn》（1974）、《Trans-Europe Express》（1977）、《The Man-Machine》（1978）奠定了电子流行乐（Synth-pop）、科技舞曲（Techno）乃至嘻哈音乐的基础，被誉为\"电子音乐教父\"。", "cause": "德国战后文化对美国摇滚乐的刻意回避，以及德国工业现代化背景下对机械美学的迷恋", "figures": ["Ralf Hütter", "Florian Schneider"], "works": ["《Autobahn》（1974）", "《Trans-Europe Express》（1977）", "《The Man-Machine》（1978）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/发电站乐队", "listen": "https://www.youtube.com/results?search_query=Kraftwerk+Autobahn", "score": ""}, "importance": 3}, {"id": "ME-0047", "year": 1976, "yearEnd": 1979, "era": "contemporary", "region": ["GB", "US"], "tags": ["朋克", "DIY文化", "摇滚"], "title": "朋克运动：性手枪与反建制摇滚", "body": "1976—1977年，以英国乐队性手枪（Sex Pistols）和冲撞乐队（The Clash）为代表的朋克运动席卷英美，以粗粝的三和弦音乐、激进的反建制态度和DIY（自己动手）文化挑战摇滚商业化。朋克直接催生了后朋克（Post-punk）、新浪潮（New Wave）和独立摇滚（Indie Rock）等流派，重塑了流行音乐的文化生态。", "cause": "70年代英国经济萧条、高失业率与阶级矛盾，以及年轻人对商业化、精英化摇滚乐的强烈反感", "figures": ["Johnny Rotten", "Joe Strummer", "Joey Ramone"], "works": ["《无政府在英国》（Anarchy in the U.K.）", "《白色暴动》（White Riot）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/朋克摇滚", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0048", "year": 1979, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["嘻哈", "说唱", "DJ", "非裔美国人"], "title": "嘻哈音乐诞生：《说唱家乐队》首张单曲", "body": "1979年，糖山帮（Sugarhill Gang）发行单曲《嘻哈万岁》（Rapper's Delight），是嘻哈音乐的第一张商业单曲，使说唱（rap）第一次进入主流公众视野。嘻哈诞生于70年代纽约南布朗克斯区的街头文化，融合了DJ打碟、说唱、霹雳舞与涂鸦艺术，成为20世纪末最具影响力的全球流行文化现象。", "cause": "纽约南布朗克斯区的极度贫困、种族歧视与城市废墟化，以及DJ科尔·赫克（DJ Kool Herc）开创的\"破段\"（breakbeat）DJ技术", "figures": ["DJ Kool Herc", "Grandmaster Flash", "Afrika Bambaataa", "Sugarhill Gang"], "works": ["《嘻哈万岁》（Rapper's Delight，1979）", "《信使》（The Message，1982）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/嘻哈音乐", "listen": "https://www.youtube.com/results?search_query=Rapper's+Delight+Sugarhill+Gang", "score": ""}, "importance": 3}, {"id": "ME-0066", "year": 1981, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["音乐电视", "流行音乐", "媒介"], "title": "MTV 开播重塑流行音乐的视觉传播方式", "body": "1981 年 MTV 开播后，音乐录像带迅速成为流行音乐营销与审美表达的核心媒介。歌手形象、舞蹈编排、剪辑节奏与视觉叙事开始与歌曲本身同等重要，80 年代流行文化由此进入高度视觉化时代。", "cause": "有线电视扩张与青年消费市场增长，使音乐产业开始系统性投资影像化传播。", "figures": ["Michael Jackson", "Madonna"], "works": ["《Video Killed the Radio Star》", "《Thriller》"], "links": {"wiki": "https://zh.wikipedia.org/wiki/MTV", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0049", "year": 1982, "yearEnd": null, "era": "contemporary", "region": ["JP", "US"], "tags": ["技术革新", "MIDI", "数字音乐", "合成器"], "title": "MIDI协议发布：数字音乐的通用语言", "body": "1982年，乐器数字接口（MIDI，Musical Instrument Digital Interface）协议由多家乐器厂商联合发布，实现了不同电子乐器与计算机之间的互联互通。MIDI彻底改变了音乐制作的方式，使个人计算机成为音乐创作工具，催生了现代数字音乐制作（DAW）产业，是电子音乐与流行音乐生产方式的根本性革命。", "cause": "电子乐器厂商（Roland、Yamaha、Korg等）的竞争迫使行业统一通信标准，以实现乐器互联", "figures": ["Dave Smith", "Ikutaro Kakehashi"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/MIDI", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0050", "year": 1982, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["迈克尔·杰克逊", "流行音乐", "MTV", "专辑"], "title": "《颤栗》专辑：史上最畅销的音乐专辑", "body": "迈克尔·杰克逊（Michael Jackson）于1982年发行专辑《颤栗》（Thriller），最终全球销量超过6600万张，成为史上最畅销的音乐专辑。《颤栗》MV以电影级制作重新定义了音乐录影带的形式，而迈克尔·杰克逊的演出风格（太空步等）深刻影响了此后数十年的流行文化。", "cause": "MTV频道（1981年创立）对视觉化音乐营销的巨大推动，以及迈克尔·杰克逊与制作人昆西·琼斯（Quincy Jones）的完美合作", "figures": ["Michael Jackson", "Quincy Jones"], "works": ["专辑《颤栗》（Thriller）", "《比利·简》（Billie Jean）", "《颤栗》（Thriller MV）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/颤栗_(专辑)", "listen": "https://www.youtube.com/results?search_query=Michael+Jackson+Thriller", "score": ""}, "importance": 3}, {"id": "ME-0085", "year": 1982, "yearEnd": null, "era": "contemporary", "region": ["JP", "NL"], "tags": ["数字音频", "唱片工业", "媒介"], "title": "CD 商业化推动数字音频载体普及", "body": "1982 年，索尼与飞利浦推动 CD 商业化发行。作为高保真数字音频介质，CD 在 80 至 90 年代迅速成为主流唱片载体，改变了录音、再版、收藏与家庭聆听的标准，并为后来的计算机音频处理打下基础。", "cause": "唱片工业追求更高保真度、更强耐用性与更易标准化的大规模复制介质。", "figures": ["Sony", "Philips"], "works": ["Compact Disc"], "links": {"wiki": "https://zh.wikipedia.org/wiki/CD", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0051", "year": 1991, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["垃圾摇滚", "涅槃乐队", "独立摇滚"], "title": "涅槃乐队《永远的青春》：垃圾摇滚席卷主流", "body": "1991年9月，涅槃乐队（Nirvana）发行专辑《从不介意》（Nevermind），单曲《青春气息》（Smells Like Teen Spirit）迅速席卷全球，将西雅图的垃圾摇滚（Grunge）推入主流市场，终结了80年代华丽金属（Glam Metal）的统治。主唱科特·柯本（Kurt Cobain）的反商业姿态成为整个90年代青年的精神象征。", "cause": "80年代商业化摇滚的空洞与过度精致引发年轻一代的强烈厌倦，西雅图DIY音乐圈的独立精神积累", "figures": ["Kurt Cobain", "Dave Grohl", "Krist Novoselic"], "works": ["专辑《从不介意》（Nevermind）", "《青春气息》（Smells Like Teen Spirit）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/从不介意", "listen": "https://www.youtube.com/results?search_query=Nirvana+Smells+Like+Teen+Spirit", "score": ""}, "importance": 3}, {"id": "ME-0086", "year": 1995, "yearEnd": null, "era": "contemporary", "region": ["DE"], "tags": ["数字压缩", "互联网", "音频格式"], "title": "MP3 普及改变音乐分发与携带方式", "body": "90 年代中后期，MP3 作为高压缩率数字音频格式被广泛采用，大幅降低了音乐在网络传播和个人存储中的成本。它改变了人们获取、收藏和分享音乐的方式，也直接推动了随后的 P2P 与数字下载时代。", "cause": "互联网普及与个人电脑存储能力提升，使高压缩数字音频格式具备大规模传播条件。", "figures": ["Fraunhofer Society"], "works": ["MP3"], "links": {"wiki": "https://zh.wikipedia.org/wiki/MP3", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0052", "year": 1999, "yearEnd": 2001, "era": "contemporary", "region": ["US"], "tags": ["数字化", "Napster", "唱片工业危机", "互联网"], "title": "Napster引爆数字音乐革命与版权危机", "body": "1999年，肖恩·范宁（Shawn Fanning）创建P2P文件共享软件Napster，用户可免费分享MP3音乐文件，峰值用户超8000万。唱片工业通过法律手段于2001年迫使Napster关闭，但数字盗版风潮已不可遏制。Napster彻底瓦解了传统唱片销售模式，直接催生了此后iTunes（2003）和Spotify（2008）等合法数字音乐平台的出现。", "cause": "互联网与MP3压缩格式的普及，青年一代对低廉便捷获取音乐的强烈需求，以及唱片公司对数字化转型的迟滞反应", "figures": ["Shawn Fanning", "Lars Ulrich（Metallica，起诉Napster）"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/Napster", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0067", "year": 1999, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["数字分发", "P2P", "版权"], "title": "Napster 让 P2P 音乐共享进入大众视野", "body": "Napster 让用户能够通过 P2P 网络快速共享 MP3 文件，直接冲击传统唱片工业的销售模式。它虽然很快因版权诉讼而关闭，但已经不可逆地改变了人们对数字音乐获取方式的预期，并推动合法数字平台出现。", "cause": "MP3 普及、校园网络扩张与用户对低成本即时获取音乐的需求，共同促成 P2P 爆发。", "figures": ["Shawn Fanning", "Metallica"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/Napster", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0087", "year": 2005, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["流媒体视频", "平台", "传播"], "title": "YouTube 改写音乐视频与歌曲传播路径", "body": "YouTube 使音乐录像带、现场片段、翻唱与用户二创能够以极低门槛全球传播。它重塑了歌曲走红机制，弱化了传统电视和唱片分发的把关作用，并为后来平台算法驱动的音乐传播模式铺路。", "cause": "宽带网络与用户上传平台成熟，使视频成为互联网音乐传播的核心形式之一。", "figures": ["YouTube"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/YouTube", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0088", "year": 2007, "yearEnd": null, "era": "contemporary", "region": ["JP"], "tags": ["虚拟歌手", "日本流行音乐", "软件"], "title": "初音未来推动虚拟歌手与用户共创文化扩张", "body": "2007 年发布的初音未来将 Vocaloid 软件与角色形象深度绑定，使“软件音源 + 虚拟偶像 + 用户创作社区”形成完整生态。它不仅改变了日本网络音乐生产方式，也让虚拟歌手成为全球数字音乐文化的重要现象。", "cause": "语音合成技术、二次创作社区和视频平台传播结合，催生出参与式的网络音乐生产模式。", "figures": ["Hatsune Miku", "Crypton Future Media"], "works": ["初音未来"], "links": {"wiki": "https://zh.wikipedia.org/wiki/初音未来", "listen": "", "score": ""}, "importance": 2}, {"id": "ME-0053", "year": 2008, "yearEnd": null, "era": "contemporary", "region": ["SE"], "tags": ["流媒体", "Spotify", "数字音乐", "订阅制"], "title": "Spotify上线：流媒体订阅模式重塑音乐产业", "body": "瑞典公司Spotify于2008年正式上线，以\"按需流媒体+订阅制\"彻底颠覆了音乐分发模式，使听众可以合法、即时地访问数千万首曲目。到2020年代，Spotify拥有超过5亿用户，成为全球最大的音乐流媒体平台。流媒体的崛起使单曲和专辑的重要性发生根本转变，也引发了关于版税分配公平性的持续争议。", "cause": "Napster危机后唱片工业对合法数字分发的迫切需求，智能手机的普及，以及宽带互联网的全球覆盖", "figures": ["Daniel Ek", "Martin Lorentzon"], "works": [], "links": {"wiki": "https://zh.wikipedia.org/wiki/Spotify", "listen": "", "score": ""}, "importance": 3}, {"id": "ME-0054", "year": 2012, "yearEnd": null, "era": "contemporary", "region": ["KR"], "tags": ["K-pop", "全球化", "韩国流行音乐", "YouTube"], "title": "《江南Style》：K-pop走向全球的象征", "body": "2012年，韩国歌手鸟叔（PSY）发行《江南Style》（Gangnam Style），成为YouTube历史上第一个播放量破10亿的视频，引发全球狂欢。这首歌标志着韩国流行音乐（K-pop）走向真正意义上的全球化，也印证了社交媒体时代音乐传播方式的根本性变革。", "cause": "韩国娱乐产业对流媒体与社交媒体的早期布局，YouTube全球化平台的巨大传播力，以及夸张的舞蹈与视觉内容的病毒式传播特性", "figures": ["PSY"], "works": ["《江南Style》（Gangnam Style）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/江南Style", "listen": "https://www.youtube.com/watch?v=9bZkp7q19f0", "score": ""}, "importance": 2}, {"id": "ME-0055", "year": 2023, "yearEnd": null, "era": "contemporary", "region": ["US"], "tags": ["人工智能", "AI音乐", "技术革新", "版权"], "title": "AI生成音乐引发产业与版权新争议", "body": "2023年，Suno、Udio等AI音乐生成平台相继上线，用户可通过文字提示生成高质量音乐作品。同年，一首由AI模拟德雷克（Drake）声音创作的歌曲《心》（Heart on My Sleeve）在各大平台病毒式传播，随即遭版权下架，引发了关于AI训练数据版权、声音权利与音乐创作归属的全球性讨论。这是音乐史上又一次由技术颠覆引发的产业革命。", "cause": "大型语言模型与扩散模型（Diffusion Model）技术成熟，以及互联网上海量音乐训练数据的可及性", "figures": ["Mikey Shulman（Suno CEO）"], "works": ["《Heart on My Sleeve》（AI生成，2023）"], "links": {"wiki": "https://zh.wikipedia.org/wiki/人工智能音乐生成", "listen": "", "score": ""}, "importance": 3}]}}};
